import React, { useEffect, useState } from 'react';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, TextField, Box, Typography, CircularProgress } from '@material-ui/core';
import { getItems, createItem, updateItem, deleteItem } from '../services/ApiService';
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  root: {
    padding: theme.spacing(3),
  },
  form: {
    display: 'flex',
    gap: theme.spacing(2),
    marginBottom: theme.spacing(2),
  },
}));

export default function ItemManagement() {
  const classes = useStyles();
  const [items, setItems] = useState([]);
  const [newItem, setNewItem] = useState({ name: '', retailPrice: 0, wholesalePrice: 0, stock: 0 });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    setLoading(true);
    getItems().then(res => {
      if (res.error) {
        setError('Failed to load items');
      } else {
        setItems(res.data);
      }
      setLoading(false);
    });
  }, []);

  const addItem = () => {
    createItem(newItem).then(res => {
      if (!res.error) {
        setItems([...items, res.data]);
        setNewItem({ name: '', retailPrice: 0, wholesalePrice: 0, stock: 0 });
      } else {
        setError('Failed to create item');
      }
    });
  };

  const handleUpdate = (id, item) => {
    updateItem(id, item).then(res => {
      if (!res.error) {
        setItems(items.map(i => (i.id === id ? res.data : i)));
      } else {
        setError('Failed to update item');
      }
    });
  };

  const handleDelete = (id) => {
    deleteItem(id).then(res => {
      if (!res.error) {
        setItems(items.filter(i => i.id !== id));
      } else {
        setError('Failed to delete item');
      }
    });
  };

  if (loading) return <CircularProgress />;
  if (error) return <Typography color="error">{error}</Typography>;

  return (
    <div className={classes.root}>
      <Typography variant="h4" gutterBottom>Item Management</Typography>
      <Box className={classes.form}>
        <TextField
          label="Item Name"
          value={newItem.name}
          onChange={e => setNewItem({ ...newItem, name: e.target.value })}
        />
        <TextField
          label="Retail Price"
          type="number"
          value={newItem.retailPrice}
          onChange={e => setNewItem({ ...newItem, retailPrice: parseFloat(e.target.value) })}
        />
        <TextField
          label="Wholesale Price"
          type="number"
          value={newItem.wholesalePrice}
          onChange={e => setNewItem({ ...newItem, wholesalePrice: parseFloat(e.target.value) })}
        />
        <TextField
          label="Stock"
          type="number"
          value={newItem.stock}
          onChange={e => setNewItem({ ...newItem, stock: parseInt(e.target.value) })}
        />
        <Button onClick={addItem} color="primary" variant="contained">Add Item</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Name</TableCell>
            <TableCell>Retail Price</TableCell>
            <TableCell>Wholesale Price</TableCell>
            <TableCell>Stock</TableCell>
            <TableCell>Actions</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {items.map(item => (
            <TableRow key={item.id}>
              <TableCell>{item.name}</TableCell>
              <TableCell>{item.retailPrice}</TableCell>
              <TableCell>{item.wholesalePrice}</TableCell>
              <TableCell>{item.stock}</TableCell>
              <TableCell>
                <Button onClick={() => handleUpdate(item.id, { ...item, name: item.name + ' Updated' })} color="primary">Update</Button>
                <Button onClick={() => handleDelete(item.id)} color="secondary">Delete</Button>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
